39	func installedEntryToInfo(e registry.InstalledEntry) pluginInfo {
40		ts := ""
41		if !e.InstalledAt.IsZero() {
42			ts = e.InstalledAt.UTC().Format("2006-01-02T15:04:05Z")
43		}
44		return pluginInfo{
