53	func (s *Server) listMCPServersFor(workingDir string) ([]mcpServerEntry, error) {
54		libPath := s.libraryPathFor(workingDir)
55		if libPath == "" {
56			return []mcpServerEntry{}, nil
57		}
58		data, err := os.ReadFile(filepath.Join(libPath, "mcp-servers", "registry.yml"))
59		if err != nil {
60			return []mcpServerEntry{}, nil
61		}
62		var reg mcpServerRegistryFile
63		if err := yaml.Unmarshal(data, &reg); err != nil {
64			return nil, err
65		}
66		if reg.Servers == nil {
67			return []mcpServerEntry{}, nil
68		}
69		return reg.Servers, nil
70	}
